function [S,R,err] = ZD2SR(Z,D,V)

    z = [Z(1:end-1,:); ones(1,size(Z,2))]./Z(end,:);
    t = V(:,1).*z(1,:) + V(:,2).*z(2,:) + V(:,3).*z(3,:) + V(:,4).*z(4,:) + V(:,5).*z(5,:);
    q = t(1,:).*t(2,:).*t(3,:) + 2*t(4,:).*t(5,:).*t(6,:) - t(1,:).*t(6,:).^2 - t(2,:).*t(5,:).^2 - t(3,:).*t(4,:).^2;
    q = 0.5./sqrt(q);
    L1 = q.*(t(2,:).*t(3,:) - t(6,:).^2);
    L2 = q.*(t(1,:).*t(3,:) - t(5,:).^2);
    L3 = q.*(t(1,:).*t(2,:) - t(4,:).^2);
    L4 = L1 + L2 - 2*q.*(t(5,:).*t(6,:) - t(3,:).*t(4,:));
    L5 = L1 + L3 - 2*q.*(t(4,:).*t(6,:) - t(2,:).*t(5,:));
    L6 = L2 + L3 - 2*q.*(t(4,:).*t(5,:) - t(1,:).*t(6,:));
    T7 = L1.*L6.^2 + L2.^2.*L5 + L3.^2.*L4 + 2*L2.*L3.*L6 - L1.*L2.*L6 - L1.*L3.*L6 - L2.*L3.*L4 - L2.*L3.*L5 - L2.*L5.*L6 - L3.*L4.*L6;
    c = 1 - 2*(abs(t(7,:) + T7) < abs(t(7,:) - T7));
    L = [L1; L2; L3; L4; L5; L6].*c;
    T = L2T(L(1,:),L(2,:),L(3,:),L(4,:),L(5,:),L(6,:));
    e = vecnorm(t(10:11,:) - T);

    k = 38; % number of true roots
    [e,I] = sort(e);
    L = L(:,I(1:k)); % filter out false roots
    err = e(1:k);
    c = ~any(imag(L),1) & all(L>0,1); % real and positive roots only
    L = L(:,c);
    err = err(c);

    nr = size(L,2);
    S = nan(3,size(D,2),nr);
    R = nan(3,size(D,1),nr);

    r = 0; % number of real solutions
    for i = 1:nr
        [Sr,Rr,flag] = DL2SR(D,L(:,i));
        if ~flag
            r = r + 1;
            S(:,:,r) = Sr;
            R(:,:,r) = Rr;
            err(r) = err(i);
        end
    end
    S = S(:,:,1:r);
    R = R(:,:,1:r);

end



function T = L2T(L1,L2,L3,L4,L5,L6)

    T = [%-L2.^2 - L3.^2 - L6.^2 + 2*L2.*L3 + 2*L2.*L6 + 2*L3.*L6;
         %-L1.^2 - L3.^2 - L5.^2 + 2*L1.*L3 + 2*L1.*L5 + 2*L3.*L5;
         %-L1.^2 - L2.^2 - L4.^2 + 2*L1.*L2 + 2*L1.*L4 + 2*L2.*L4;
         %L3.^2 + 2*L3.*L4 - L1.*L3 + L1.*L2 - L1.*L6 - L2.*L3 - L2.*L5 - L3.*L5 - L3.*L6 + L5.*L6;
         %L2.^2 + 2*L2.*L5 - L1.*L2 + L1.*L3 - L1.*L6 - L2.*L3 - L2.*L4 - L2.*L6 - L3.*L4 + L4.*L6;
         %L1.^2 + 2*L1.*L6 - L1.*L2 + L2.*L3 - L1.*L3 - L1.*L4 - L1.*L5 - L2.*L5 - L3.*L4 + L4.*L5;
         %L1.*L6.^2 + L2.^2.*L5 + L3.^2.*L4 + 2*L2.*L3.*L6 - L1.*L2.*L6 - L1.*L3.*L6 - L2.*L3.*L4 - L2.*L3.*L5 - L2.*L5.*L6 - L3.*L4.*L6;
         %L1.^2.*L6 + L2.*L5.^2 + L3.^2.*L4 + 2*L1.*L3.*L5 - L1.*L2.*L5 - L1.*L3.*L4 - L1.*L3.*L6 - L1.*L5.*L6 - L2.*L3.*L5 - L3.*L4.*L5;
         %L1.^2.*L6 + L2.^2.*L5 + L3.*L4.^2 + 2*L1.*L2.*L4 - L1.*L2.*L5 - L1.*L2.*L6 - L1.*L3.*L4 - L1.*L4.*L6 - L2.*L3.*L4 - L2.*L4.*L5;
         L1.^2.*L6 + L1.*L2.*L4 - L1.*L2.*L5 - L1.*L3.*L4 + L1.*L3.*L5 - L1.*L4.*L6 - L1.*L5.*L6 - L2.*L4.*L5 - L2.*L5.*L6 - L3.*L4.*L5 - L3.*L4.*L6 + L4.*L5.*L6 + L2.^2.*L5 + L3.^2.*L4 - L1.*L2.*L6 - L1.*L3.*L6 + L1.*L6.^2 - L2.*L3.*L4 - L2.*L3.*L5 + L2.*L3.*L6 + L2.*L5.^2 + L3.*L4.^2;
         -L1.^2.*L6.^2 - L2.^2.*L5.^2 - L3.^2.*L4.^2 + 2*L1.*L2.*L5.*L6 + 2*L1.*L3.*L4.*L6 + 2*L2.*L3.*L4.*L5];

end



function [S,R,flag] = DL2SR(D,L)

    flag = 0;
    S = zeros(3,4);
    R = zeros(3,6);
    x2 = sqrt(L(1));
    S(:,2) = [x2; 0; 0];
    x3 = (L(1) + L(2) - L(4))/(2*x2);
    x3sq = x3^2;
    if L(2) < x3sq; flag = 1; return; end
    y3 = sqrt(L(2) - x3sq);
    S(:,3) = [x3; y3; 0];
    x4 = (L(1) + L(3) - L(5))/(2*x2);
    y4 = (x3^2 - 2*x3*x4 + y3^2 + L(3) - L(6))/(2*y3);
    u4sq = x4^2 + y4^2;
    if L(3) < u4sq; flag = 1; return; end
    z4 = sqrt(L(3) - u4sq);
    S(:,4) = [x4; y4; z4];
    a1 = L(1) + (D(:,1) - D(:,2))';
    a2 = L(2) + (D(:,1) - D(:,3))';
    a3 = L(3) + (D(:,1) - D(:,4))';
    R = [a1; (x2*a2 - x3*a1)./y3; ((x3*y4 - y3*x4)*a1 + x2*(y3*a3 - y4*a2))./(y3*z4)]./(2*x2);

end